import { GoogleGenAI, Type } from "@google/genai";

// Initializing the Gemini API client using the environment variable directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const summarizeArticle = async (text: string): Promise<string> => {
  try {
    const prompt = `Summarize the following political news article into 3 concise bullet points. Focus on the key facts and implications for the citizens of Kwara State. \n\n Article Text: ${text}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        maxOutputTokens: 300,
        temperature: 0.5,
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return response.text || "No summary generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Failed to generate summary. Please try again later.";
  }
};

export const getPoliticalAnalysis = async (title: string, content: string): Promise<string> => {
  try {
    const prompt = `Act as a senior political analyst for Kwara Political Hangout (KPH). Provide a deep-dive analysis of the following news story: "${title}". 
    Consider the political history of Kwara State, the potential impact on the upcoming elections, and how it affects the various interest groups in the state. 
    Content: ${content}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 1024 }
      }
    });

    return response.text || "Analysis unavailable.";
  } catch (error) {
    console.error("Analysis Error:", error);
    return "Failed to perform deep analysis.";
  }
};

export const chatWithIntelligence = async (message: string, history: { role: string, parts: { text: string }[] }[]): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: "You are the KPH Political Intelligence Assistant. You are an expert on Kwara State, Nigeria - its politics, 16 LGAs, history (Saraki era, Otoge movement, current administration), and prominent figures. Your tone is objective, analytical, yet accessible to the local community. Always prioritize factual information about Kwara State. If asked about things outside Kwara, try to relate them back to the state if possible.",
      }
    });

    const response = await chat.sendMessage({ message });
    return response.text || "I'm sorry, I couldn't process that request.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Connection to KPH Intelligence interrupted.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Bot, User, Loader2, Minimize2, Sparkles } from 'lucide-react';
import { chatWithIntelligence } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'bot', text: string }[]>([
    { role: 'bot', text: 'Welcome to KPH Intelligence. I can help you analyze Kwara politics or find information about the state. What is on your mind today?' }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      const response = await chatWithIntelligence(userMessage, []);
      setMessages(prev => [...prev, { role: 'bot', text: response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "I'm having trouble connecting to the intelligence hub. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[60] flex flex-col items-end">
      {/* Chat Window */}
      {isOpen && (
        <div className="bg-white w-[350px] md:w-[400px] h-[550px] rounded-3xl shadow-2xl border border-gray-100 flex flex-col overflow-hidden mb-4 animate-slide-up">
          {/* Header */}
          <div className="bg-kph-charcoal text-white p-5 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-kph-red rounded-xl flex items-center justify-center shadow-lg">
                <Sparkles size={20} className="text-white" />
              </div>
              <div>
                <h3 className="font-black text-sm uppercase tracking-tighter">KPH Intelligence</h3>
                <div className="flex items-center gap-1.5">
                  <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                  <span className="text-[10px] font-bold text-gray-400 uppercase">Analysis Engine Active</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
              <Minimize2 size={18} />
            </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-5 space-y-4 bg-gray-50/50">
            {messages.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-kph-red text-white shadow-md rounded-br-none' 
                    : 'bg-white border border-gray-100 text-kph-charcoal shadow-sm rounded-bl-none'
                }`}>
                  <p className="whitespace-pre-wrap">{msg.text}</p>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-gray-100 p-4 rounded-2xl shadow-sm flex items-center gap-3">
                  <Loader2 className="animate-spin text-kph-red" size={16} />
                  <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Analyzing...</span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <form onSubmit={handleSend} className="p-4 bg-white border-t border-gray-100">
            <div className="relative group">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask about Kwara politics..."
                className="w-full pl-5 pr-12 py-4 bg-gray-100 border-none rounded-2xl focus:ring-2 focus:ring-kph-red/20 outline-none transition-all text-sm font-medium"
              />
              <button 
                type="submit"
                disabled={isLoading}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-kph-charcoal text-white rounded-xl hover:bg-kph-red transition-all disabled:opacity-50"
              >
                <Send size={18} />
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Floating Toggle Button */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-16 h-16 rounded-[2rem] shadow-2xl flex items-center justify-center transition-all duration-500 hover:scale-110 active:scale-95 ${
          isOpen ? 'bg-kph-charcoal text-white rotate-90' : 'bg-kph-red text-white'
        }`}
      >
        {isOpen ? <X size={28} /> : <MessageSquare size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-6 h-6 bg-kph-charcoal text-white text-[10px] font-black rounded-full border-4 border-white flex items-center justify-center animate-bounce">
            AI
          </div>
        )}
      </button>
    </div>
  );
};

export default ChatBot;

import React from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import Home from './pages/Home';
import People from './pages/People';
import ArticleDetail from './pages/ArticleDetail';
import Contact from './pages/Contact';
