export default App;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Calendar, Share2, Sparkles, AlertCircle, Bookmark, ThumbsUp, MessageSquare, Loader2, List, ExternalLink, Send, Check, ChevronLeft, Home, MoreHorizontal, ShieldAlert } from 'lucide-react';
import Sidebar from '../components/Sidebar';
import { summarizeArticle, getPoliticalAnalysis } from '../services/geminiService';
import { NewsService } from '../services/newsService';
import { Article } from '../types';
import SEO from '../components/SEO';

interface Comment {
  id: number;
  author: string;
  text: string;
  time: string;
  avatar: string;
  likes: number;
}

const ArticleDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [scrollY, setScrollY] = useState(0);
  const [article, setArticle] = useState<Article | null>(null);
  const [pageLoading, setPageLoading] = useState(true);

  const [likes, setLikes] = useState(0);
  const [isLiked, setIsLiked] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  const [commentText, setCommentText] = useState('');
  const MAX_CHARS = 500;

  const [comments, setComments] = useState<Comment[]>([]);
  const [showShareTooltip, setShowShareTooltip] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const loadArticle = async () => {
      setPageLoading(true);
      if (id) {
        const found = await NewsService.getArticleById(id);
        setArticle(found || null);
        setLikes(Math.floor(Math.random() * 20));
      }
      setPageLoading(false);
    };
    loadArticle();
  }, [id]);

  const [summary, setSummary] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [loadingSummary, setLoadingSummary] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);

  const handleSummarize = async () => {
    if (!article) return;
    setLoadingSummary(true);
    try {
        const contentToSummarize = article.content || article.excerpt || article.title;
        const result = await summarizeArticle(contentToSummarize);
        setSummary(result);
    } catch (e) {
        console.error(e);
    } finally {
        setLoadingSummary(false);
    }
  };

  const handleAnalyze = async () => {
    if (!article) return;
    setLoadingAnalysis(true);
    try {
        const result = await getPoliticalAnalysis(article.title, article.content || article.excerpt);
        setAnalysis(result);
    } catch (e) {
        console.error(e);
    } finally {
        setLoadingAnalysis(false);
    }
  };

  const toggleLike = () => {
    if (isLiked) {
        setLikes(prev => prev - 1);
        setIsLiked(false);
    } else {
        setLikes(prev => prev + 1);
        setIsLiked(true);
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
        try {
            await navigator.share({
                title: article?.title,
                text: article?.excerpt,
                url: window.location.href,
            });
        } catch (err) {
            console.log('Share canceled');
        }
    } else {
        navigator.clipboard.writeText(window.location.href);
        setShowShareTooltip(true);
        setTimeout(() => setShowShareTooltip(false), 2000);
    }
  };

  const handleSubmitComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;

    const newComment: Comment = {
        id: Date.now(),
        author: 'Guest User',
        text: commentText,
        time: 'Just now',
        avatar: 'G',
        likes: 0
    };

    setComments([newComment, ...comments]);
    setCommentText('');
  };

  if (pageLoading) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
         <Loader2 className="w-10 h-10 text-kph-red animate-spin" />
      </div>
    );
  }

  if (!article) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-8 text-center">
        <SEO title="Article Not Found | KPH News" description="The requested article could not be found." />
        <h2 className="text-3xl font-bold text-kph-charcoal mb-4">Article Not Found</h2>
        <a href="/" className="bg-kph-red text-white px-6 py-3 rounded-lg font-bold hover:bg-red-900 transition">Go Home</a>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen pb-24 lg:pb-12 animate-fade-in relative">
        <SEO 
          title={`${article.title} | KPH News`} 
          description={article.excerpt}
          image={article.imageUrl}
          imageAlt={article.title}
          type="article"
        />

        <div className="absolute top-4 left-4 z-20 lg:hidden">
            <button onClick={() => navigate(-1)} className="bg-white/90 backdrop-blur text-kph-charcoal p-2 rounded-full shadow-md">
                <ChevronLeft size={24} />
            </button>
        </div>

        <div className="relative h-[400px] lg:h-[600px] w-full overflow-hidden">
            <img 
                src={article.imageUrl} 
                alt={article.title} 
                className="w-full h-full object-cover"
                style={{ transform: `translateY(${scrollY * 0.4}px)` }} 
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>

            <div 
                className="absolute bottom-0 left-0 w-full container mx-auto px-4 lg:px-8 pb-12 lg:pb-20 animate-slide-up"
                style={{ opacity: Math.max(0, 1 - scrollY / 400) }}
            >
                <div className="flex items-center space-x-3 mb-4 lg:mb-8">
                    <span className="bg-kph-red text-white px-4 py-1.5 text-[10px] lg:text-xs font-black uppercase rounded-lg shadow-lg tracking-widest">{article.category}</span>
                    <span className="text-gray-300 text-xs lg:text-sm font-bold tracking-wider">{article.readTime}</span>
                </div>
                <h1 className="text-3xl lg:text-6xl font-black text-white mb-6 lg:mb-10 max-w-5xl leading-tight font-serif drop-shadow-2xl">{article.title}</h1>
                <div className="flex items-center gap-6 text-gray-400 text-xs font-black uppercase tracking-widest">
                  <span className="flex items-center gap-2"><Calendar size={14} className="text-kph-red" /> {article.date}</span>
                  <span className="flex items-center gap-2">By {article.author}</span>
                </div>
            </div>
        </div>

        <div className="container mx-auto px-4 lg:px-8 py-8 lg:py-16 relative -mt-10 lg:-mt-20 z-10">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                <div className="lg:col-span-8 bg-white rounded-t-[3rem] lg:rounded-[3rem] p-8 lg:p-12 shadow-2xl shadow-gray-200/50">

                    {/* AI Insights Section */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12">
                        {/* Summary */}
                        <div className="bg-purple-50 border border-purple-100 rounded-[2.5rem] p-8 relative overflow-hidden group">
