                            <div className="flex items-center justify-between mb-6 relative z-10">
                                <h3 className="flex items-center text-purple-900 font-black text-xs uppercase tracking-[0.2em]">
                                    <Sparkles size={18} className="text-purple-600 mr-2" /> AI Smart Summary
