                                {!summary && !loadingSummary && (
                                    <button onClick={handleSummarize} className="text-[10px] font-black uppercase tracking-widest bg-purple-600 text-white px-4 py-2 rounded-xl hover:bg-purple-700 transition-colors">Generate</button>
                                )}
                            </div>
                            {loadingSummary ? (
                                <div className="flex flex-col items-center justify-center py-4 gap-3">
                                  <Loader2 className="text-purple-600 animate-spin" size={24} />
                                  <span className="text-[10px] font-black text-purple-400 uppercase tracking-widest">Processing...</span>
                                </div>
                            ) : summary ? (
                                <div className="text-sm text-purple-900/80 leading-relaxed space-y-3 relative z-10 animate-fade-in">
                                  {summary.split('\n').map((line, i) => line.trim() && <p key={i} className="flex gap-2"><span className="text-purple-600 font-bold">•</span> {line.replace(/^[-*•]\s*/, '')}</p>)}
