                            ) : (
                                <p className="text-xs text-purple-400 font-medium">Get a quick breakdown of this story in seconds.</p>
                            )}
                        </div>

                        {/* Analysis */}
                        <div className="bg-amber-50 border border-amber-100 rounded-[2.5rem] p-8 relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-amber-100/50 rounded-full -mr-12 -mt-12 group-hover:scale-150 transition-transform"></div>
                            <div className="flex items-center justify-between mb-6 relative z-10">
                                <h3 className="flex items-center text-amber-900 font-black text-xs uppercase tracking-[0.2em]">
                                    <ShieldAlert size={18} className="text-amber-600 mr-2" /> Pol. Analysis
