                                {!analysis && !loadingAnalysis && (
                                    <button onClick={handleAnalyze} className="text-[10px] font-black uppercase tracking-widest bg-amber-600 text-white px-4 py-2 rounded-xl hover:bg-amber-700 transition-colors">Analyze</button>
                                )}
                            </div>
                            {loadingAnalysis ? (
                                <div className="flex flex-col items-center justify-center py-4 gap-3">
                                  <Loader2 className="text-amber-600 animate-spin" size={24} />
                                  <span className="text-[10px] font-black text-amber-400 uppercase tracking-widest">Deep Dive...</span>
                                </div>
                            ) : analysis ? (
                                <div className="text-sm text-amber-900/80 leading-relaxed relative z-10 animate-fade-in line-clamp-4 hover:line-clamp-none transition-all">
                                  <p>{analysis}</p>
                                </div>
                            ) : (
                                <p className="text-xs text-amber-400 font-medium">Unlock deeper insights into the political implications.</p>
                            )}
                        </div>
                    </div>

                    {/* Article Content */}
                    <article className="prose prose-lg max-w-none text-gray-800 leading-relaxed font-serif">
                        <p className="lead text-xl lg:text-2xl font-bold mb-10 text-kph-charcoal font-sans border-l-[6px] border-kph-red pl-8 py-2 bg-gray-50 rounded-r-2xl">
                          {article.excerpt}
                        </p>
                        <div className="space-y-6 text-lg lg:text-xl">
                             {article.content ? (
                                <div className="content-render" dangerouslySetInnerHTML={{ __html: article.content.replace(/\n/g, '<br/><br/>') }} />
                             ) : (
                                <p>Full details are currently being curated by our editorial team. Check back shortly for updates.</p>
                             )}
                        </div>
                    </article>

                    <div className="mt-16 border-t border-gray-100 pt-16">
                        <h3 className="text-2xl font-black text-kph-charcoal mb-10 uppercase tracking-tighter">Community Discourse</h3>
                        <form onSubmit={handleSubmitComment} className="mb-12 relative">
                            <textarea 
                                value={commentText}
                                onChange={(e) => setCommentText(e.target.value)}
                                maxLength={MAX_CHARS}
