        <div className="text-center mb-12">
            <div className="w-24 h-24 bg-gray-900 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-[0_0_50px_rgba(139,0,0,0.3)] border border-kph-red/30 group">
