        </div>
        <form onSubmit={handleUnlock} className="space-y-8">
           <div className="relative">
             <input 
              type="password" value={pin} onChange={(e) => { setPin(e.target.value); setError(false); }}
              className={`w-full bg-white/5 border-2 ${error ? 'border-red-500/50 text-red-500 shadow-[0_0_20px_rgba(239,68,68,0.2)]' : 'border-white/10 text-white focus:border-kph-red focus:bg-white/10'} rounded-3xl px-4 py-6 text-center text-4xl tracking-[1.5em] focus:outline-none font-mono transition-all duration-300 backdrop-blur-xl`}
