import { Article } from '../types';
import { supabase } from './supabaseClient';

export interface AdUnit {
  enabled: boolean;
  imageUrl: string;
  linkUrl: string;
  altText: string;
  title?: string;
  stats: {
    clicks: number;
    impressions: number;
    lastUpdated: string;
  };
}

export interface AdConfig {
  homeBanner: AdUnit;
  sidebarAd: AdUnit;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: 'Admin' | 'Editor' | 'Writer' | 'Suspended';
  joinedDate: string;
  status: 'Active' | 'Pending' | 'Banned';
}

export interface GlobalAlert {
  enabled: boolean;
  message: string;
  type: 'info' | 'warning' | 'critical';
}

export interface WriterArticle {
  id: string;
  title: string;
  category: string;
  content: string;
  imageUrl: string;
  author: string;
  date: string;
  status: 'Published' | 'Draft';
}

const DEFAULT_AD_UNIT: AdUnit = { 
  enabled: false, 
  imageUrl: '', 
  linkUrl: '#', 
  altText: 'Advertisement', 
  title: 'Sponsored Content',
  stats: { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() } 
};

const DEFAULT_AD_CONFIG: AdConfig = {
  homeBanner: { ...DEFAULT_AD_UNIT },
  sidebarAd: { ...DEFAULT_AD_UNIT }
};

const LocalDB = {
  get: (key: string) => {
    try {
      const val = localStorage.getItem(`kph_${key}`);
      return val ? JSON.parse(val) : null;
    } catch (e) { return null; }
  },
  set: (key: string, val: any) => {
    try {
      localStorage.setItem(`kph_${key}`, JSON.stringify(val));
    } catch (e) { console.error("Local storage set failed", e); }
  }
};

export const AdminService = {
  async getAdConfig(): Promise<AdConfig> {
    // Priority 1: Local Cache (Instant)
    const cached = LocalDB.get('ads');

    try {
      // Background: Sync from Supabase
      const { data, error } = await supabase.from('ads').select('*').eq('id', 1).maybeSingle();
      if (!error && data) {
        const config: AdConfig = {
          homeBanner: { ...DEFAULT_AD_UNIT, ...(data.homeBanner || {}) },
          sidebarAd: { ...DEFAULT_AD_UNIT, ...(data.sidebarAd || {}) }
        };
        LocalDB.set('ads', config);
        return config;
      }
    } catch (e) {
      console.warn("Supabase fetch failed, using local fallback.");
    }

    return cached || DEFAULT_AD_CONFIG;
  },

  async saveAdConfig(config: AdConfig) {
    // Ensure local persistence first
    LocalDB.set('ads', config);

    try {
      // Attempt to save to Supabase. If columns are missing, this will fail but local stay updated.
      // We wrap the payload to be more resilient to schema changes
      const { error } = await supabase.from('ads').upsert({ 
        id: 1, 
        homeBanner: config.homeBanner, 
        sidebarAd: config.sidebarAd,
        updated_at: new Date().toISOString()
      }, { onConflict: 'id' });

      if (error) {
        // Log but don't throw - the local save is the primary for the current session
        console.warn("Supabase Sync Delayed (Schema mismatch or offline). Saved locally.");
      }
    } catch (e: any) {
      console.error("Critical Sync Error:", e.message);
    }
  },

  async recordAdImpression(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.impressions += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async recordAdClick(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.clicks += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async resetAdStats() {
    const config = await this.getAdConfig();
    config.homeBanner.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    config.sidebarAd.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    await this.saveAdConfig(config);
  },

  // --- Featured Articles ---
  async getFeaturedArticleIds(): Promise<string[]> {
    const cached = LocalDB.get('featured_ids');
    try {
      const { data, error } = await supabase.from('featured_articles').select('article_id');
      if (!error && data) {
        const ids = data.map(i => i.article_id);
        LocalDB.set('featured_ids', ids);
        return ids;
      }
    } catch (e) {}
    return cached || [];
  },

  async setFeaturedArticle(articleId: string, isFeatured: boolean = true) {
    const current = LocalDB.get('featured_ids') || [];
    const updated = isFeatured ? [...new Set([...current, articleId])] : current.filter((id: string) => id !== articleId);
    LocalDB.set('featured_ids', updated);
    try {
      if (isFeatured) await supabase.from('featured_articles').upsert({ article_id: articleId });
      else await supabase.from('featured_articles').delete().eq('article_id', articleId);
    } catch (e) {}
  },

  // --- Site Config & Alerts ---
  async getGlobalAlert(): Promise<GlobalAlert | null> {
    const cached = LocalDB.get('global_alert');
    try {
      const { data, error } = await supabase.from('site_config').select('value').eq('key', 'global_alert').maybeSingle();
      if (!error && data) {
        LocalDB.set('global_alert', data.value);
        return data.value;
      }
    } catch (e) {}
    return cached;
  },

  async setGlobalAlert(alert: GlobalAlert | null) {
    LocalDB.set('global_alert', alert);
    try { await supabase.from('site_config').upsert({ key: 'global_alert', value: alert }); } catch (e) {}
  },

  async getUsers(): Promise<User[]> {
    const cached = LocalDB.get('users') || [];
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (!error && data) {
        LocalDB.set('users', data);
        return data;
      }
    } catch (e) {}
    return cached;
  },

  async addUser(user: Partial<User>) {
    const newUser = { ...user, id: user.id || `u_${Date.now()}`, joinedDate: new Date().toISOString(), status: 'Active' };
    LocalDB.set('users', [...(LocalDB.get('users') || []), newUser]);
    try { await supabase.from('users').insert([newUser]); } catch (e) {}
  },

  async deleteUser(userId: string) {
