    } catch (e) { return null; }
  },
  set: (key: string, val: any) => {
    try {
      localStorage.setItem(`kph_${key}`, JSON.stringify(val));
    } catch (e) { console.error("Local storage set failed", e); }
  }
};

export const AdminService = {
  async getAdConfig(): Promise<AdConfig> {
    const cached = LocalDB.get('ads');

    try {
      // Try fetching from the 'ads' table. 
      // We handle the case where columns might be different or table missing.
      const { data, error } = await supabase.from('ads').select('*').eq('id', 1).maybeSingle();

      if (!error && data) {
        // If the table uses a 'value' column for JSON config (common pattern)
        const remoteConfig = data.value || data; 

        const config: AdConfig = {
          homeBanner: { ...DEFAULT_AD_UNIT, ...(remoteConfig.homeBanner || remoteConfig.home_banner || {}) },
          sidebarAd: { ...DEFAULT_AD_UNIT, ...(remoteConfig.sidebarAd || remoteConfig.sidebar_ad || {}) }
        };

        // Update local cache with remote data if remote exists
        LocalDB.set('ads', config);
        return config;
      }
    } catch (e) {
      console.warn("Supabase sync issue. Operating on local cache.");
    }

    return cached || DEFAULT_AD_CONFIG;
  },

  async saveAdConfig(config: AdConfig) {
    // 1. Instant Local Save (Ensures UI updates to "Configured" immediately)
    LocalDB.set('ads', config);

    try {
      // 2. Best-effort Remote Sync
      // We attempt a generic upsert. If the columns 'homeBanner' etc don't exist,
      // we try to save into a 'value' column as a JSON blob.

      // Try specific columns first (as the error suggested they were expected)
      const { error: colError } = await supabase.from('ads').upsert({ 
        id: 1, 
        homeBanner: config.homeBanner, 
        sidebarAd: config.sidebarAd,
        updated_at: new Date().toISOString()
      }, { onConflict: 'id' });

      // If specific columns fail, try saving to a generic 'value' or 'data' column
      if (colError && (colError.message.includes('column') || colError.code === '42703')) {
         console.warn("Retrying save to generic 'value' column due to schema mismatch...");
         await supabase.from('ads').upsert({ 
           id: 1, 
           value: config,
           updated_at: new Date().toISOString()
         }, { onConflict: 'id' });
      }
    } catch (e: any) {
      console.error("Remote Save Interrupted:", e.message);
    }
  },

  async recordAdImpression(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.impressions += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async recordAdClick(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.clicks += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async resetAdStats() {
    const config = await this.getAdConfig();
    config.homeBanner.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    config.sidebarAd.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    await this.saveAdConfig(config);
  },

  // --- Featured Articles ---
  async getFeaturedArticleIds(): Promise<string[]> {
