import React, { useState, useEffect, useRef } from 'react';
import { 
  LayoutDashboard, FileText, BarChart2, Settings, LogOut, Plus, Search, 
  Bell, Menu, Edit3, Trash2, Save, ArrowLeft, Check, X, ChevronDown, 
  Smartphone, Monitor, Loader2, Image as ImageIcon, Video, Globe, 
  Eye, MessageSquare, ThumbsUp, Calendar, Filter, MoreVertical, 
  CloudUpload, Sparkles, Send, TrendingUp
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import Logo from '../components/Logo';
import { AdminService, WriterArticle } from '../services/adminService';
import { UploadService } from '../services/uploadService';

const StatusBadge = ({ status }: { status: string }) => {
  const styles: any = {
    'Published': 'bg-green-50 text-green-600 border-green-100',
    'Draft': 'bg-gray-100 text-gray-500 border-gray-200',
    'Review': 'bg-amber-50 text-amber-600 border-amber-100'
  };
  return (
    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${styles[status] || styles['Draft']}`}>
      {status}
    </span>
  );
};

const Dashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState('stories');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [showEditor, setShowEditor] = useState(false);
  const [articles, setArticles] = useState<WriterArticle[]>([]);
  const [toast, setToast] = useState<string | null>(null);
  const [isPublishing, setIsPublishing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);

  // Editor State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newArticle, setNewArticle] = useState({ 
    title: '', 
    category: 'Politics', 
    content: '', 
    imageUrl: '',
    videoUrl: '',
    excerpt: '',
    status: 'Draft' as const
  });

  const navigate = useNavigate();
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadArticles();
  }, []);

  const loadArticles = async () => {
    const data = await AdminService.getWriterArticles();
    setArticles(data || []);
  };

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const handleMediaUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await UploadService.uploadMedia(file);
      if (file.type.startsWith('video/')) {
        setNewArticle(prev => ({ ...prev, videoUrl: url, imageUrl: '' }));
        showToast('Video deployed to Cloudinary');
      } else {
        setNewArticle(prev => ({ ...prev, imageUrl: url, videoUrl: '' }));
        showToast('Cover image optimized & stored');
      }
    } finally {
      setIsUploading(false);
    }
  };

  const handlePublish = async (status: 'Published' | 'Draft' = 'Published') => {
     if (!newArticle.title.trim()) return showToast("Headline is required");
     setIsPublishing(true);
     try {
       await AdminService.publishArticle({
         ...newArticle,
         id: editingId || undefined,
         author: 'Sarah Johnson', // Simulated Identity
         status: status
       });
       showToast(status === 'Published' ? "Article live on KPH Network!" : "Draft saved to cloud");
       setShowEditor(false);
       resetEditor();
       loadArticles();
     } finally {
       setIsPublishing(false);
     }
  };

  const resetEditor = () => {
    setNewArticle({ title: '', category: 'Politics', content: '', imageUrl: '', videoUrl: '', excerpt: '', status: 'Draft' });
    setEditingId(null);
  };

  const handleEdit = (article: WriterArticle) => {
    setEditingId(article.id);
    setNewArticle({
      title: article.title,
      category: article.category,
      content: article.content,
      imageUrl: article.imageUrl,
      videoUrl: (article as any).videoUrl || '',
      excerpt: (article as any).excerpt || '',
      status: article.status
    });
    setShowEditor(true);
  };

  if (showEditor) {
    return (
      <div className="bg-white min-h-screen flex flex-col animate-fade-in font-sans">
        {/* Editor Toolbar */}
        <header className="border-b px-8 h-20 flex items-center justify-between sticky top-0 bg-white/80 backdrop-blur-xl z-[60]">
           <div className="flex items-center gap-6">
              <button onClick={() => { setShowEditor(false); resetEditor(); }} className="p-3 hover:bg-gray-100 rounded-2xl transition-all"><ArrowLeft size={20} /></button>
              <div className="h-8 w-[1px] bg-gray-100"></div>
              <div>
                <h2 className="font-black text-lg uppercase tracking-tighter leading-none">Studio</h2>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Editorial Mode</p>
              </div>
           </div>
           <div className="flex items-center gap-3">
              <button 
                onClick={() => handlePublish('Draft')} 
                disabled={isPublishing}
                className="px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest text-gray-500 hover:bg-gray-50 transition-all border border-gray-100"
              >
                Save Draft
              </button>
              <button 
                onClick={() => handlePublish('Published')} 
                disabled={isPublishing || isUploading} 
                className="bg-gray-900 text-white px-8 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-black transition-all shadow-xl shadow-gray-200 active:scale-95 disabled:opacity-50"
              >
                {isPublishing ? <Loader2 className="animate-spin" size={16} /> : <Globe size={16} />} 
                Push to Live
              </button>
           </div>
        </header>

        <div className="flex-1 flex overflow-hidden">
           {/* Editor Main Canvas */}
           <main className="flex-1 overflow-y-auto bg-white p-8 lg:p-20">
              <div className="max-w-4xl mx-auto space-y-12">
                 <input 
                   type="text" 
                   value={newArticle.title} 
                   onChange={e => setNewArticle({...newArticle, title: e.target.value})} 
                   placeholder="Write a powerful headline..." 
                   className="w-full text-5xl lg:text-6xl font-black border-none outline-none placeholder-gray-100 tracking-tighter"
                 />

                 <div className="flex flex-wrap items-center gap-6 pb-8 border-b border-gray-50">
                    <div className="flex items-center gap-3 bg-gray-50 px-4 py-2 rounded-2xl border border-gray-100">
                      <StatusBadge status={newArticle.status} />
                      <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Article Status</span>
                    </div>
                    <select 
                      value={newArticle.category} 
                      onChange={e => setNewArticle({...newArticle, category: e.target.value})} 
                      className="bg-white border-2 border-gray-100 rounded-2xl px-5 py-2.5 font-black text-[10px] uppercase tracking-widest focus:border-gray-900 outline-none transition-all"
                    >
                       <option>Politics</option><option>Media</option><option>News</option><option>People</option>
                    </select>
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-widest hover:text-gray-900 transition-colors"
                    >
                       <CloudUpload size={18} /> {newArticle.imageUrl || newArticle.videoUrl ? 'Replace Media' : 'Add Hero Media'}
                    </button>
                    <input ref={fileInputRef} type="file" className="hidden" accept="image/*,video/*" onChange={handleMediaUpload} />
                 </div>

                 {isUploading && (
                   <div className="w-full h-64 bg-gray-50 rounded-[2.5rem] border-2 border-dashed border-gray-100 flex flex-col items-center justify-center gap-4">
                      <Loader2 className="animate-spin text-gray-900" size={32} />
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Optimizing Assets for Delivery...</p>
                   </div>
                 )}

                 {(newArticle.imageUrl || newArticle.videoUrl) && !isUploading && (
                   <div className="relative group rounded-[2.5rem] overflow-hidden shadow-2xl">
                      {newArticle.videoUrl ? (
                        <video src={newArticle.videoUrl} controls className="w-full h-auto" />
                      ) : (
                        <img src={newArticle.imageUrl} className="w-full h-[450px] object-cover" />
                      )}
                      <button 
                        onClick={() => setNewArticle(prev => ({...prev, imageUrl: '', videoUrl: ''}))}
                        className="absolute top-6 right-6 p-3 bg-black/50 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-md"
                      >
                        <X size={20} />
                      </button>
                   </div>
                 )}

                 <textarea 
                   value={newArticle.content} 
                   onChange={e => setNewArticle({...newArticle, content: e.target.value})}
                   placeholder="Start your story here. Use Markdown or plain text..." 
                   className="w-full h-[600px] text-xl border-none outline-none leading-relaxed text-gray-800 placeholder-gray-100 resize-none font-serif"
                 />
              </div>
           </main>

           {/* Editor Metadata Sidebar */}
           <aside className="hidden xl:flex w-96 border-l bg-gray-50/50 flex-col p-10 space-y-10">
              <div className="space-y-4">
                 <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Publishing Strategy</h4>
                 <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-gray-900 uppercase">Search Excerpt</label>
                       <textarea 
                         rows={4}
                         value={newArticle.excerpt}
                         onChange={e => setNewArticle({...newArticle, excerpt: e.target.value})}
                         placeholder="A brief summary for cards and SEO..."
                         className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-gray-300 resize-none"
                       />
                    </div>
                    <div className="pt-4 border-t border-gray-50">
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-3">Estimated Reach</p>
                       <div className="flex items-center justify-between">
                          <span className="text-2xl font-black tracking-tighter text-gray-900">1.2k+</span>
                          <TrendingUp size={20} className="text-green-500" />
                       </div>
                    </div>
                 </div>
              </div>

              <div className="bg-gray-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full blur-2xl -mr-12 -mt-12"></div>
                 <h4 className="text-[10px] font-black uppercase tracking-widest mb-6 flex items-center gap-2"><Sparkles size={14} className="text-amber-400" /> AI Assistant</h4>
                 <p className="text-xs text-gray-400 leading-relaxed mb-6">Need help with a headline or summarizing this article for politics enthusiasts?</p>
                 <button className="w-full bg-white text-gray-900 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-gray-100 transition-all">Get Suggestions</button>
              </div>
           </aside>
        </div>

        {toast && (
          <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-8 py-4 rounded-3xl shadow-xl flex items-center gap-4 animate-slide-up border border-white/10 backdrop-blur-xl">
            <Check size={18} className="text-green-500" />
            <span className="text-sm font-black uppercase tracking-wider">{toast}</span>
          </div>
        )}
      </div>
    );
