import { Article } from '../types';
import { supabase } from './supabaseClient';

export interface AdUnit {
  enabled: boolean;
  imageUrl: string;
  linkUrl: string;
  altText: string;
  title?: string;
  stats: {
    clicks: number;
    impressions: number;
    lastUpdated: string;
  };
}

export interface AdConfig {
  homeBanner: AdUnit;
  sidebarAd: AdUnit;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: 'Admin' | 'Editor' | 'Writer' | 'Suspended';
  joinedDate: string;
  status: 'Active' | 'Pending' | 'Banned';
}

export interface GlobalAlert {
  enabled: boolean;
  message: string;
  type: 'info' | 'warning' | 'critical';
}

export interface WriterArticle {
  id: string;
  title: string;
  category: string;
  content: string;
  imageUrl: string;
  videoUrl?: string;
  excerpt?: string;
  author: string;
  date: string;
  status: 'Published' | 'Draft';
  views?: number;
}

const DEFAULT_AD_UNIT: AdUnit = { 
  enabled: false, 
  imageUrl: '', 
  linkUrl: '#', 
  altText: 'Advertisement', 
  title: 'Sponsored Content',
  stats: { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() } 
};

const DEFAULT_AD_CONFIG: AdConfig = {
  homeBanner: { ...DEFAULT_AD_UNIT },
  sidebarAd: { ...DEFAULT_AD_UNIT }
};

const LocalDB = {
  get: (key: string) => {
    try {
      const val = localStorage.getItem(`kph_${key}`);
      return val ? JSON.parse(val) : null;
    } catch (e) { return null; }
  },
  set: (key: string, val: any) => {
    try {
      localStorage.setItem(`kph_${key}`, JSON.stringify(val));
    } catch (e) { console.error("Local storage set failed", e); }
  }
};

export const AdminService = {
  // --- Ad Management ---
  async getAdConfig(): Promise<AdConfig> {
    try {
      const { data, error } = await supabase.from('ads').select('*').eq('id', 1).maybeSingle();
      if (!error && data) {
        const remoteConfig = data.value || data; 
        return {
          homeBanner: { ...DEFAULT_AD_UNIT, ...(remoteConfig.homeBanner || {}) },
          sidebarAd: { ...DEFAULT_AD_UNIT, ...(remoteConfig.sidebarAd || {}) }
        };
      }
    } catch (e) {}
    return LocalDB.get('ads') || DEFAULT_AD_CONFIG;
  },

  async saveAdConfig(config: AdConfig) {
    LocalDB.set('ads', config);
    try {
      await supabase.from('ads').upsert({ id: 1, value: config }, { onConflict: 'id' });
    } catch (e) {}
  },

  async recordAdImpression(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.impressions += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async recordAdClick(slot: 'homeBanner' | 'sidebarAd') {
    const config = await this.getAdConfig();
    config[slot].stats.clicks += 1;
    config[slot].stats.lastUpdated = new Date().toISOString();
    await this.saveAdConfig(config);
  },

  async resetAdStats() {
    const config = await this.getAdConfig();
    config.homeBanner.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    config.sidebarAd.stats = { clicks: 0, impressions: 0, lastUpdated: new Date().toISOString() };
    await this.saveAdConfig(config);
  },

  // --- Article Management (Writer Portal Real Data) ---
  async getWriterArticles(): Promise<WriterArticle[]> {
    try {
      const { data, error } = await supabase
        .from('writer_articles')
        .select('*')
        .order('date', { ascending: false });

      if (!error && data) {
        LocalDB.set('writer_articles', data);
        return data;
      }
    } catch (e) {}
    return LocalDB.get('writer_articles') || [];
  },

  async publishArticle(article: Partial<WriterArticle>) {
    const id = article.id || `art_${Date.now()}`;
    const payload = {
      ...article,
      id,
      date: article.date || new Date().toISOString(),
      views: article.views || 0,
      status: article.status || 'Published'
    };

    try {
      const { error } = await supabase.from('writer_articles').upsert(payload);
      if (error) throw error;

      // Update local cache
      const current = await this.getWriterArticles();
      const updated = [payload as WriterArticle, ...current.filter(a => a.id !== id)];
      LocalDB.set('writer_articles', updated);
    } catch (e: any) {
      console.error("Publishing error:", e.message);
      // Fallback to local
      const current = LocalDB.get('writer_articles') || [];
      LocalDB.set('writer_articles', [payload, ...current.filter((a: any) => a.id !== id)]);
    }
  },

  async deleteArticle(articleId: string) {
    try {
      await supabase.from('writer_articles').delete().eq('id', articleId);
      const current = await this.getWriterArticles();
      LocalDB.set('writer_articles', current.filter(a => a.id !== articleId));
    } catch (e) {}
  },

  // --- Featured Articles ---
  async getFeaturedArticleIds(): Promise<string[]> {
    try {
      const { data, error } = await supabase.from('featured_articles').select('article_id');
      if (!error && data) return data.map(i => i.article_id);
    } catch (e) {}
    return LocalDB.get('featured_ids') || [];
  },

  async setFeaturedArticle(articleId: string) {
    try {
      await supabase.from('featured_articles').upsert({ article_id: articleId });
      LocalDB.set('featured_ids', [articleId]);
    } catch (e) {}
  },

  // --- Identity & Config ---
  async getUsers(): Promise<User[]> {
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (!error && data) return data;
    } catch (e) {}
    return LocalDB.get('users') || [];
  },

  async addUser(user: Partial<User>) {
    try {
      await supabase.from('users').insert([{ ...user, joinedDate: new Date().toISOString(), status: 'Active' }]);
    } catch (e) {}
  },

  async deleteUser(userId: string) {
    try {
      await supabase.from('users').delete().eq('id', userId);
    } catch (e) {}
  },

  async getGlobalAlert(): Promise<GlobalAlert | null> {
    try {
      const { data, error } = await supabase.from('site_config').select('value').eq('key', 'global_alert').maybeSingle();
      if (!error && data) return data.value;
    } catch (e) {}
    return LocalDB.get('global_alert');
  },

  async setGlobalAlert(alert: GlobalAlert | null) {
    try {
      await supabase.from('site_config').upsert({ key: 'global_alert', value: alert });
    } catch (e) {}
  },

  async addSubscriber(email: string) {
    try { await supabase.from('subscribers').insert([{ email }]); } catch (e) {}
  },

  async addMessage(message: any) {
    try { await supabase.from('messages').insert([message]); } catch (e) {}
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
