const StatusBadge = ({ status }: { status: string }) => {
  const styles: any = {
    'Published': 'bg-green-50 text-green-600 border-green-100',
    'Draft': 'bg-gray-100 text-gray-400 border-gray-200',
    'Review': 'bg-amber-50 text-amber-600 border-amber-100'
  };
