const Dashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState('stories');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [showEditor, setShowEditor] = useState(false);
  const [articles, setArticles] = useState<WriterArticle[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [toast, setToast] = useState<string | null>(null);

  // Editor State
  const [isPublishing, setIsPublishing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [newArticle, setNewArticle] = useState({ 
    title: '', 
    category: 'Politics', 
    content: '', 
    imageUrl: '',
    videoUrl: '',
    excerpt: '',
    status: 'Draft' as 'Published' | 'Draft'
  });

  const navigate = useNavigate();
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadArticles();
  }, []);

  const loadArticles = async () => {
    setIsLoading(true);
    const data = await AdminService.getWriterArticles();
    setArticles(data);
    setIsLoading(false);
  };

  const showToast = (msg: string) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3000);
  };

  const handleMediaUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const url = await UploadService.uploadMedia(file);
      if (file.type.startsWith('video/')) {
        setNewArticle(prev => ({ ...prev, videoUrl: url, imageUrl: '' }));
        showToast('HD Video deployed to Cloudinary');
      } else {
        setNewArticle(prev => ({ ...prev, imageUrl: url, videoUrl: '' }));
        showToast('Image optimized & secured');
      }
    } catch (err) {
      showToast('Media upload failed');
    } finally {
      setIsUploading(false);
    }
  };

  const handlePublish = async (status: 'Published' | 'Draft' = 'Published') => {
    if (!newArticle.title.trim()) return showToast("Article title is mandatory");
    setIsPublishing(true);
    try {
      await AdminService.publishArticle({
        ...newArticle,
        id: editingId || undefined,
        author: 'Admin Writer', // In a real app, this would come from session
        status: status,
        date: new Date().toISOString()
      });
      showToast(status === 'Published' ? "Article is now live!" : "Draft preserved in database");
      setShowEditor(false);
      resetEditor();
      loadArticles();
    } catch (err) {
      showToast('Database synchronization error');
    } finally {
      setIsPublishing(false);
    }
  };

  const resetEditor = () => {
    setNewArticle({ title: '', category: 'Politics', content: '', imageUrl: '', videoUrl: '', excerpt: '', status: 'Draft' });
    setEditingId(null);
  };

  const handleEdit = (article: WriterArticle) => {
    setEditingId(article.id);
    setNewArticle({
      title: article.title,
      category: article.category,
      content: article.content,
      imageUrl: article.imageUrl,
      videoUrl: article.videoUrl || '',
      excerpt: article.excerpt || '',
      status: article.status
    });
    setShowEditor(true);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Permanent deletion cannot be undone. Proceed?")) {
      await AdminService.deleteArticle(id);
      showToast("Article purged from database");
      loadArticles();
    }
  };

  // Studio Mode UI
  if (showEditor) {
    return (
      <div className="bg-white min-h-screen flex flex-col animate-fade-in font-sans selection:bg-kph-red selection:text-white">
        <header className="border-b px-8 h-20 flex items-center justify-between sticky top-0 bg-white/95 backdrop-blur-xl z-[60]">
           <div className="flex items-center gap-6">
              <button onClick={() => { setShowEditor(false); resetEditor(); }} className="p-3 hover:bg-gray-100 rounded-2xl transition-all"><ArrowLeft size={20} /></button>
              <div className="h-8 w-[1px] bg-gray-100"></div>
              <div>
                <h2 className="font-black text-lg uppercase tracking-tighter leading-none">Studio</h2>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Creation & Revision</p>
              </div>
           </div>
