import { GoogleGenAI } from "@google/genai";
import { Article } from '../types';
import { AdminService } from './adminService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CACHE_DURATION = 15 * 60 * 1000;
interface CacheEntry {
  timestamp: number;
  data: Article[];
}
const newsCache: Record<string, CacheEntry> = {};
const articleDetailCache: Map<string, Article> = new Map();

function getContextualImage(title: string, category: string, index: number): string {
  const t = title.toLowerCase();
  const dateStr = new Date().toISOString().split('T')[0];
  return `https://picsum.photos/seed/kwara_${index}_${dateStr}/800/600`;
}

function parseGeminiResponse(text: string, category: string): Article[] {
  const articles: Article[] = [];
  const itemRegex = /<NEWS_ITEM>([\s\S]*?)<\/NEWS_ITEM>/g;
  let match;
  let index = 0;

  while ((match = itemRegex.exec(text)) !== null) {
    const block = match[1];
    const extract = (tag: string) => {
      const r = new RegExp(`<${tag}>([\\s\\S]*?)<\/${tag}>`, 'i');
      const m = block.match(r);
      return m ? m[1].trim() : '';
    };

    const title = extract('HEADLINE').replace(/^"/, '').replace(/"$/, '');
    const summary = extract('SUMMARY');
    const content = extract('CONTENT');
    const date = extract('DATE') || new Date().toLocaleDateString();
    const sourceUrl = extract('SOURCE_URL');

    if (title && summary) {
      const id = `gen_${Date.now()}_${index}`;
      const article: Article = {
        id,
        title,
        excerpt: summary,
        content: content.length > 50 ? content : `<p>${summary}</p>`,
        category: category === 'General' ? 'News' : category,
        author: extract('AUTHOR') || 'KPH Staff',
        date,
        readTime: '4 min read',
        imageUrl: extract('IMAGE_URL') || getContextualImage(title, category, index),
        sourceUrl,
        sourceName: sourceUrl ? 'Verified Source' : 'KPH Exclusive'
      };
      articles.push(article);
      articleDetailCache.set(id, article);
      index++;
    }
  }
  return articles;
}

export const NewsService = {
  async getLatestNews(topic: string = 'General'): Promise<Article[]> {
    const cacheKey = `latest_${topic}`;
    const cached = newsCache[cacheKey];
    if (cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
      return cached.data;
    }

    let articles: Article[] = [];

    // 1. Fetch Real Published Articles from Writer Portal
    try {
      const writerArticles = await AdminService.getWriterArticles();
      const published = writerArticles
        .filter(a => a.status === 'Published' && (topic === 'General' || a.category === topic))
        .map(a => ({
          ...a,
          readTime: '5 min read',
          sourceName: 'KPH Original'
        } as Article));

      articles = [...published];
      published.forEach(p => articleDetailCache.set(p.id, p));
    } catch (e) {}

    // 2. Supplement with AI-curated web news if needed
    if (articles.length < 10) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Find 10 latest news reports about ${topic} in Kwara State, Nigeria. Format: <NEWS_ITEM><HEADLINE>...</HEADLINE><SUMMARY>...</SUMMARY><CONTENT>...</CONTENT><DATE>...</DATE><AUTHOR>...</AUTHOR><SOURCE_URL>...</SOURCE_URL></NEWS_ITEM>`,
          config: { tools: [{ googleSearch: {} }] }
        });
        if (response.text) {
          const aiArticles = parseGeminiResponse(response.text, topic);
          articles = [...articles, ...aiArticles];
        }
      } catch (e) {}
    }

    newsCache[cacheKey] = { timestamp: Date.now(), data: articles };
    return articles;
  },

  async getArticleById(id: string): Promise<Article | undefined> {
    if (articleDetailCache.has(id)) return articleDetailCache.get(id);

    // Check if it's a writer article directly
    const writerArticles = await AdminService.getWriterArticles();
    const found = writerArticles.find(a => a.id === id);
    if (found) {
      const art = { ...found, readTime: '5 min read', sourceName: 'KPH Original' } as Article;
      articleDetailCache.set(id, art);
      return art;
    }
    return undefined;
  },

  async searchNews(query: string): Promise<Article[]> {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Search for news matching "${query}" in Kwara State. Format: <NEWS_ITEM><HEADLINE>...</HEADLINE><SUMMARY>...</SUMMARY><CONTENT>...</CONTENT><DATE>...</DATE><AUTHOR>...</AUTHOR><SOURCE_URL>...</SOURCE_URL></NEWS_ITEM>`,
      config: { tools: [{ googleSearch: {} }] }
    });
    return response.text ? parseGeminiResponse(response.text, 'Search') : [];
  }
};

export interface Article {
  id: string;
  title: string;
  excerpt: string;
  content?: string;
  category: 'Politics' | 'Media' | 'People' | 'News' | string;
  author: string;
  date: string;
  readTime: string;
  imageUrl: string;
  videoUrl?: string; // Support for Cloudinary Video
  sourceUrl?: string;
