import { GoogleGenAI } from "@google/genai";
import { Article } from '../types';
import { AdminService } from './adminService';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const CACHE_DURATION = 5 * 60 * 1000; // 5 minute freshness
interface CacheEntry {
  timestamp: number;
  data: Article[];
}
const newsCache: Record<string, CacheEntry> = {};
const articleDetailCache: Map<string, Article> = new Map();

function parseGeminiResponse(text: string, category: string): Article[] {
  const articles: Article[] = [];
  const itemRegex = /<NEWS_ITEM>([\s\S]*?)<\/NEWS_ITEM>/g;
  let match;
  let index = 0;

  while ((match = itemRegex.exec(text)) !== null) {
    const block = match[1];
    const extract = (tag: string) => {
      const r = new RegExp(`<${tag}>([\\s\\S]*?)<\/${tag}>`, 'i');
      const m = block.match(r);
      return m ? m[1].trim() : '';
    };

    const title = extract('HEADLINE').replace(/^"/, '').replace(/"$/, '');
    const summary = extract('SUMMARY');
    const content = extract('CONTENT');
    const date = extract('DATE') || new Date().toLocaleDateString();

    if (title && summary) {
      const id = `gen_${Date.now()}_${index}`;
      const article: Article = {
        id,
        title,
        excerpt: summary,
        content: content.length > 50 ? content : `<p>${summary}</p>`,
        category: category === 'General' ? 'News' : category,
        author: extract('AUTHOR') || 'KPH Staff',
        date,
        readTime: '4 min read',
        imageUrl: `https://picsum.photos/seed/${id}/800/600`,
        sourceName: 'AI Intelligence'
      };
      articles.push(article);
      articleDetailCache.set(id, article);
      index++;
    }
  }
  return articles;
}

export const NewsService = {
  /**
   * Primary fetcher for the public news feed.
   * Priority: 1. Supabase (Real Writer Data) -> 2. AI Curation (Web news if DB is empty)
   */
  async getLatestNews(topic: string = 'General'): Promise<Article[]> {
    const cacheKey = `latest_${topic}`;
    const cached = newsCache[cacheKey];
    if (cached && (Date.now() - cached.timestamp < CACHE_DURATION)) {
      return cached.data;
    }

    let articles: Article[] = [];

    try {
      // 1. Fetch Real Published Articles from Supabase via AdminService
      const writerArticles = await AdminService.getWriterArticles();

      // Filter for published status and category
      const published = writerArticles
        .filter(a => a.status === 'Published')
        .filter(a => topic === 'General' || a.category.toLowerCase() === topic.toLowerCase())
        .map(a => ({
          ...a,
          readTime: a.readTime || '5 min read',
          sourceName: 'KPH News'
        } as Article));

      articles = [...published];
      published.forEach(p => articleDetailCache.set(p.id, p));
    } catch (e) {
      console.error("Database fetch failed, falling back to AI curation.", e);
    }

    // 2. Supplement with AI news ONLY if we have very little real data
    if (articles.length < 5) {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Provide 8 breaking news reports about ${topic} in Kwara State, Nigeria. Ensure they are relevant for today. Format: <NEWS_ITEM><HEADLINE>...</HEADLINE><SUMMARY>...</SUMMARY><CONTENT>...</CONTENT><DATE>...</DATE><AUTHOR>...</AUTHOR></NEWS_ITEM>`,
          config: { tools: [{ googleSearch: {} }] }
        });
        if (response.text) {
          const aiArticles = parseGeminiResponse(response.text, topic);
          articles = [...articles, ...aiArticles];
        }
      } catch (e) {}
    }

    // Deduplicate and Sort by Date (newest first)
    articles = articles.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    newsCache[cacheKey] = { timestamp: Date.now(), data: articles };
    return articles;
  },

  async getArticleById(id: string): Promise<Article | undefined> {
    if (articleDetailCache.has(id)) return articleDetailCache.get(id);

    // Check database if not in cache
    const writerArticles = await AdminService.getWriterArticles();
    const found = writerArticles.find(a => a.id === id);
    if (found) {
      const art = { ...found, readTime: '5 min read', sourceName: 'KPH News' } as Article;
      articleDetailCache.set(id, art);
      return art;
    }
    return undefined;
  },

  async searchNews(query: string): Promise<Article[]> {
    const dbArticles = await this.getLatestNews('General');
    const localResults = dbArticles.filter(a => 
      a.title.toLowerCase().includes(query.toLowerCase()) || 
      a.excerpt.toLowerCase().includes(query.toLowerCase())
    );

    if (localResults.length > 5) return localResults;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Search for news about "${query}" in Kwara State. Format: <NEWS_ITEM><HEADLINE>...</HEADLINE><SUMMARY>...</SUMMARY><CONTENT>...</CONTENT><DATE>...</DATE><AUTHOR>...</AUTHOR></NEWS_ITEM>`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const aiResults = response.text ? parseGeminiResponse(response.text, 'Search') : [];
      return [...localResults, ...aiResults];
    } catch (e) {
      return localResults;
    }
  }
};

