      {toast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-8 py-4 rounded-[2rem] shadow-2xl flex items-center gap-4 animate-slide-up border border-white/10 backdrop-blur-xl">
          <Zap size={18} className="text-amber-400" />
